## 重构运算符
以下分别为 重构对象的加减 , 自增 , >> 和()
```c++
#include <iostream>
using namespace std;
class Person{
//实现的操作是 ---> 类与类相加返回int , 类与int相加返回int
	public:
		Person(int id){
			this->id = id;
		};
	friend  int operator+(const Person &person,const Person &person1){
            return person1.id + person.id;
        };
	friend	int operator+(const Person &person ,  int id){
			return person.id + id;
		};
		int id;
};
int main (){
    Person person(1);
    Person person1(2);
    cout << "person.id+person.id = "<< person1+person << endl;
	cout << "person.id+int = " << person1+10 << endl;
	cout << "int + person.id = " << 10+person1 << endl;
    return 0;
}

```
```c++
#include <iostream>
using namespace std;
class Distance{
	public:
	int foot;
	int meter;
	//无参数的构造函数
	Distance(){
		foot = 0;
		meter = 0;
	}
	//有参数的构造函数
	Distance(int foot , int meter){
		this->foot = foot;
		this->meter = meter;
	}
	//tostring函数
	void tostring(){
		cout << "this distrance is { foot:"<< this->foot << ",meter" << this->meter << "}" << endl;
	}
	//重载负号运算符
	Distance operator-(){
		this->foot--;
		this->meter--;
		return Distance(foot,meter);
	}
	//重载前后自减运算符
	//前置运算:
	Distance operator--(){
		this->foot--;
		return Distance(foot,meter);
	}
	//后置运算
	Distance operator--(int){
		this->meter--;
		return Distance(foot,meter);
	}
};
int main (){
	Distance distance(10,15);
	distance.tostring();
	distance--;
	distance.tostring();
	--distance;
	distance.tostring();
	return 0;
}


```
